svg.script:
(() => {
  const TIE_KNOT = { x: 188, y: 263 };
const HEAD_LAYER_IDS = new Set(["ears-layer", "head-tufts", "head-layer", "face-layer"]);
const BODY_LAYERS_SKIP = new Set(["feet-layer", "foot-front-layer", "rig-guides"]);
const VIEW_W = 374;
const TOP_CHAIN = ["A", "L", "C", "D", "E", "R", "G"];
const RAW_ANCHORS = {
      A: { x: 65, y: 153 },
      L: { x: 137.77, y: 162.56 },
      C: { x: 171.37, y: 154.02 },
      D: { x: 189.69, y: 147.65 },
      E: { x: 210.43, y: 157.48 },
      R: { x: 240.66, y: 162.63 },
      G: { x: 309, y: 153 }
    };
const LOOK_BASE = {
      cheekD: "M65 153 C97 159 136 168 172 154 C181 150 193 147 202 154 C238 168 277 159 309 153 C331 178 336 221 303 246 C270 268 104 268 71 246 C38 221 43 178 65 153Z",
      headCapD: "M64 153 C64 88 116 48 187 48 C258 48 310 88 310 153 C310 214 257 253 187 253 C117 253 64 214 64 153Z",
      leftCreaseD: "M62 238 C70 250 84 256 100 256",
      rightCreaseD: "M312 238 C304 250 290 256 274 256"
    };
const RIGHT_HEAD_CAP_D = "M64 153 C66.12 89.55 117.55 49.81 187 48 C267.24 48 328.48 88 310 153 C310 214 257 253 187 253 C117 253 64 214 64 153Z";
const LEFT_HEAD_CAP_D = "M64 153 C45.52 88 106.76 48 187 48 C256.45 49.81 307.88 89.55 310 153 C310 214 257 253 187 253 C117 253 64 214 64 153Z";
const FRONT_TAIL = [
      [331, 178, 336, 221, 303, 246],
      [270, 268, 104, 268, 71, 246],
      [38, 221, 43, 178, 65, 153]
    ];
const LEFT_TAIL = [
      [320.06, 180.73, 321.87, 218.27, 303, 246],
      [270, 268, 104, 268, 71, 246],
      [35.12, 221, 40.6, 178, 65, 153]
    ];
const RIGHT_TAIL = [
      [333.4, 178, 338.88, 221, 303, 246],
      [270, 268, 104, 268, 71, 246],
      [52.13, 218.27, 53.94, 180.73, 65, 153]
    ];
const PITCH_UP = { axis: -25.5, lower: 3.6, faceDy: -21.5, faceSy: 0.93, blushDy: -22.41, earDy: 12, tuftDy: 12 };
const PITCH_DOWN = { axis: 26, lower: -7.9, faceDy: 24.5, faceSy: 1, blushDy: 24.5, earDy: -10, tuftDy: -2 };
const BASE_ARMS = { x: 187, y: 294, scale: 1, scaleX: 1, scaleY: 1, rotate: -2, opacity: 1 };
const ARMS_POSES = {
      left: { x: 187, y: 291, scale: 1, scaleX: 1, scaleY: 1, rotate: -5, opacity: 1 },
      center: { x: 187, y: 291, scale: 1, scaleX: 1, scaleY: 1, rotate: -0.75, opacity: 1 },
      right: { x: 187, y: 291, scale: 1, scaleX: 1, scaleY: 1, rotate: 3.25, opacity: 1 }
    };
const BUBBLE_POSES = {
      left: { x: -195, y: 40, scale: 0.76 },
      right: { x: 345, y: 42, scale: 0.76 }
    };
const BROW_PATHS = {
      left: {
        base: [[127, 116], [137, 108], [148, 110], [154, 118]],
        focus: [[130, 118], [139, 113], [149, 114], [156, 120]],
        happy: [[126, 114], [137, 104], [149, 106], [156, 114]]
      },
      right: {
        base: [[247, 116], [237, 108], [226, 110], [220, 118]],
        focus: [[244, 118], [235, 113], [225, 114], [218, 120]],
        happy: [[248, 114], [237, 104], [225, 106], [218, 114]]
      }
    };
const DEFAULTS = {
      speed: 1,
      tapPower: 1,
      turnPower: 1,
      glancePower: 0.72,
      typingPower: 1,
      bodySway: 1,
      focusMouthInset: 10,
      happyMouthInset: 1.5,
      focusBrow: 0.82,
      happyBrow: 0.72,
      armsTint: 0.08,
      armsBrightness: 1.005,
      armsContrast: 0.985,
      armsOutlineOpacity: 1,
      armsOutlineWidth: 1,
      showSessionBoxes: true,
      showGuides: false,
      showTapMarks: false,
      freezePose: false
    };
const CYCLE_MS = 10400;
const LEFT_START_MS = 0;
const RIGHT_START_MS = 5200;

  const state = {
    ...DEFAULTS,
    speed: 1,
    showSessionBoxes: true,
    showGuides: false,
    showTapMarks: false,
    freezePose: false
  };
  const lookState = { yaw: 0, pitch: 0 };
  let rafId = null;
  let paused = false;
  let loopStartTime = performance.now();
  let currentPose = null;

  const stageSvg = document.currentScript && document.currentScript.ownerSVGElement;
  if (!stageSvg) return;
  const masterLayer = stageSvg.querySelector("#masterLayer");
  const sessionLayer = stageSvg.querySelector("#sessionLayer");
  const root = masterLayer?.querySelector("#hamster-flat-master-v11") || masterLayer;
  const leftSessionBubble = stageSvg.querySelector("#leftSessionBubble");
  const rightSessionBubble = stageSvg.querySelector("#rightSessionBubble");
  const bubbleLeft = {
    root: leftSessionBubble,
    shellFill: stageSvg.querySelector("#leftShellFill"),
    shellStroke: stageSvg.querySelector("#leftShellStroke"),
    icon: [stageSvg.querySelector("#leftChevronOpen"), stageSvg.querySelector("#leftSlash"), stageSvg.querySelector("#leftChevronClose")],
    dots: [stageSvg.querySelector("#leftDot0"), stageSvg.querySelector("#leftDot1"), stageSvg.querySelector("#leftDot2"), stageSvg.querySelector("#leftDot3")],
    line1Dot: stageSvg.querySelector("#leftLine1Dot"),
    cursor: stageSvg.querySelector("#leftCursor"),
    lines: [
      { el: stageSvg.querySelector("#leftLine0A"), max: 68, x: 73, y: 100, start: 0.16, span: 0.12 },
      { el: stageSvg.querySelector("#leftLine0B"), max: 39, x: 151, y: 100, start: 0.25, span: 0.10 },
      { el: stageSvg.querySelector("#leftLine1A"), max: 128, x: 92, y: 132, start: 0.34, span: 0.15 },
      { el: stageSvg.querySelector("#leftLine2A"), max: 39, x: 73, y: 164, start: 0.52, span: 0.10 },
      { el: stageSvg.querySelector("#leftLine2B"), max: 38, x: 121, y: 164, start: 0.60, span: 0.10 },
      { el: stageSvg.querySelector("#leftLine3A"), max: 69, x: 73, y: 196, start: 0.70, span: 0.11 },
      { el: stageSvg.querySelector("#leftLine3B"), max: 69, x: 151, y: 196, start: 0.79, span: 0.12 }
    ]
  };
  const bubbleRight = {
    root: rightSessionBubble,
    shellGlow: stageSvg.querySelector("#rightShellGlow"),
    shellStroke: stageSvg.querySelector("#rightShellStroke"),
    chat: stageSvg.querySelector("#rightInnerChat"),
    chatDots: [stageSvg.querySelector("#rightChatDot0"), stageSvg.querySelector("#rightChatDot1"), stageSvg.querySelector("#rightChatDot2")],
    bottomDots: [stageSvg.querySelector("#rightBottomDot0"), stageSvg.querySelector("#rightBottomDot1"), stageSvg.querySelector("#rightBottomDot2")],
    checks: [stageSvg.querySelector("#rightCheck0"), stageSvg.querySelector("#rightCheck1"), stageSvg.querySelector("#rightCheck2")],
    tasks: [stageSvg.querySelector("#rightTask0"), stageSvg.querySelector("#rightTask1"), stageSvg.querySelector("#rightTask2")]
  };
  const tapMarkLayer = stageSvg.querySelector("#tapMarkLayer");
  const leftTapMarks = stageSvg.querySelector("#leftTapMarks");
  const rightTapMarks = stageSvg.querySelector("#rightTapMarks");
  const guideLayer = stageSvg.querySelector("#guideLayer");
  const weightAxis = stageSvg.querySelector("#weightAxis");
  const weightDot = stageSvg.querySelector("#weightDot");
  const lookRay = stageSvg.querySelector("#lookRay");

  if (!root) return;
  setProgress(0);
  const reduceMotion = window.matchMedia && window.matchMedia("(prefers-reduced-motion: reduce)").matches;
  if (!reduceMotion) play();

  window.__cloudlingWorking2Session = { play, pause, replay, setProgress, snapshot };
  window.__cloudlingReplayWorking2Session = replay;
  window.__cloudlingSetWorking2SessionProgress = setProgress;
  window.__clawdSetLowPowerPaused = (value) => {
    paused = Boolean(value);
    if (paused) pause();
    else if (!reduceMotion) play();
  };

  function play() {
    paused = false;
    if (rafId !== null) return;
    loopStartTime = performance.now() - (currentPose ? currentPose.ms : 0) / Math.max(state.speed, 0.001);
    rafId = requestAnimationFrame(tick);
  }

  function pause() {
    paused = true;
    if (rafId !== null) {
      cancelAnimationFrame(rafId);
      rafId = null;
    }
  }

  function replay() {
    loopStartTime = performance.now();
    setProgress(0);
    if (!reduceMotion) play();
  }

  function setProgress(progress) {
    const p = clamp(Number(progress) || 0, 0, 1);
    render(p * CYCLE_MS);
  }

  function tick(now) {
    if (paused) {
      rafId = null;
      return;
    }
    render((now - loopStartTime) * state.speed);
    rafId = requestAnimationFrame(tick);
  }

  function render(elapsedMs) {
    const pose = poseAt(elapsedMs);
    currentPose = pose;
    applyBodyPose(pose);
    applyExpression(pose);
    applyFeetPose(pose);
    applySessions(pose);
    applyGuides(pose);
    applyArmsColorTune();
    applyArmsOutlineTune();
  }

  function snapshot() {
    const pose = currentPose || poseAt(0);
    return {
      phase: pose.phase,
      activeSession: pose.activeSession,
      progress: round(pose.cycleProgress, 3),
      lookYaw: round(pose.lookYaw, 2),
      supportSide: round(pose.side, 2),
      tappingFoot: pose.tappingFoot,
      arms: armsForPose(pose),
      lineCount: stageSvg.querySelectorAll("#crossedArmsHandLineLayer path").length
    };
  }

function poseAt(elapsedMs) {
      const ms = positiveMod(elapsedMs, CYCLE_MS);
      let phase = "leftTyping";
      let phaseLabel = "左 session 输出";
      let side = -1;
      let look = 0;
      let activeSession = "left";
      let leftTyping = 0;
      let rightTyping = 0;
      let tapGate = 0;
      let focusExpr = 0;
      let happyExpr = 0;

      if (ms < 3600) {
        const p = ms / 3600;
        phase = "leftTyping";
        phaseLabel = "看着左气泡输出 · 右脚踏拍";
        look = -heldGlance(p);
        leftTyping = easeOutCubic(p);
        tapGate = workGate(p);
        focusExpr = expressionGate(p);
      } else if (ms < 4300) {
        const p = (ms - 3600) / 700;
        phase = "leftHappy";
        phaseLabel = "左边完成 · 回正脸开心一下";
        look = -returnLook(p);
        leftTyping = 1;
        happyExpr = happyPulse(p);
      } else if (ms < 5200) {
        const p = easeInOutCubic((ms - 4300) / 900);
        phase = "turnRight";
        phaseLabel = "身体换向右边";
        side = mix(-1, 1, p);
        activeSession = "switch";
        leftTyping = 1;
      } else if (ms < 8800) {
        const p = (ms - 5200) / 3600;
        phase = "rightTyping";
        phaseLabel = "看着右气泡输出 · 左脚踏拍";
        side = 1;
        look = heldGlance(p);
        activeSession = "right";
        rightTyping = easeOutCubic(p);
        tapGate = workGate(p);
        focusExpr = expressionGate(p);
      } else if (ms < 9500) {
        const p = (ms - 8800) / 700;
        phase = "rightHappy";
        phaseLabel = "右边完成 · 回正脸开心一下";
        side = 1;
        look = returnLook(p);
        activeSession = "right";
        rightTyping = 1;
        happyExpr = happyPulse(p);
      } else {
        const p = easeInOutCubic((ms - 9500) / 900);
        phase = "turnLeft";
        phaseLabel = "身体换向左边";
        side = mix(1, -1, p);
        activeSession = "switch";
        rightTyping = 1;
      }

      const cycleT = ms / CYCLE_MS;
      const tapClock = positiveMod(elapsedMs, 720) / 720;
      const tap = Math.pow(Math.max(0, Math.sin(Math.PI * 2 * tapClock)), 0.68) * tapGate;
      const landing = Math.pow(Math.max(0, Math.sin(Math.PI * 2 * tapClock - 0.38)), 8) * tapGate;
      const turn = state.turnPower;
      const sway = state.bodySway;
      const bodyShiftX = side * 8.4 * turn + Math.sin(Math.PI * 2 * tapClock + 0.8) * 1.05 * sway * tapGate;
      const bodyY = 1.8 + tap * 1.45 * sway - landing * 0.82 * sway;
      const bodyRotate = side * 1.75 * turn + Math.sin(Math.PI * 2 * tapClock + 1.05) * 0.38 * sway * tapGate;
      const pivotX = mix(112, 262, (side + 1) / 2);
      const supportLeft = clamp(-side, 0, 1);
      const supportRight = clamp(side, 0, 1);
      const tappingFoot = tapGate > 0.02 ? (side < 0 ? "right" : "left") : "none";
      const headLook = look * turn * state.glancePower;
      const lookYaw = headLook * 100;
      const leftActive = activeSession === "left" ? 1 : 0;
      const rightActive = activeSession === "right" ? 1 : 0;

      return {
        ms,
        cycleProgress: cycleT,
        phase,
        phaseLabel,
        side,
        look,
        headLook,
        lookYaw,
        activeSession,
        leftTyping,
        rightTyping,
        tap,
        tapGate,
        landing,
        bodyShiftX,
        bodyY,
        bodyRotate,
        pivotX,
        supportLeft,
        supportRight,
        tappingFoot,
        heelLift: tap * 9.5 * state.tapPower,
        footRotate: (2 * tapGate + tap * 9 * state.tapPower),
        leftActive,
        rightActive,
        focusExpr,
        happyExpr,
        weightAxisX: pivotX + bodyShiftX * 0.18
      };
    }

function applyBodyPose(pose) {
      const bodyTransform = `rotate(${fmt(pose.bodyRotate)} ${fmt(pose.pivotX + pose.bodyShiftX)} 356) translate(${fmt(pose.bodyShiftX)} ${fmt(pose.bodyY)})`;
      applyIdleLookGeometry(pose);
      const fittedArms = armsForPose(pose);
      for (const child of Array.from(root.children)) {
        if (BODY_LAYERS_SKIP.has(child.id)) continue;
        const base = child.dataset.baseTransform || "";
        if (child.id === "tie") {
          child.setAttribute("transform", tieTransform(pose, base));
        } else if (child.id === "crossedArmsLayer") {
          child.setAttribute("transform", `${bodyTransform} ${armsTransform(fittedArms)}`.trim());
          child.setAttribute("opacity", fmt(fittedArms.opacity));
        } else if (HEAD_LAYER_IDS.has(child.id)) {
          const lookLayer = idleLookLayerTransform(child.id);
          child.setAttribute("transform", `${bodyTransform} ${lookLayer} ${base}`.trim());
        } else {
          child.setAttribute("transform", `${bodyTransform} ${base}`.trim());
        }
      }
    }

function tieTransform(pose, base) {
      const mapped = applyBodyPoint(TIE_KNOT, pose);
      const dx = mapped.x - TIE_KNOT.x;
      const dy = mapped.y - TIE_KNOT.y;
      const ang = pose.bodyRotate * 0.25;
      return `translate(${fmt(dx)} ${fmt(dy)}) rotate(${fmt(ang)} ${TIE_KNOT.x} ${TIE_KNOT.y}) ${base}`.trim();
    }

function applyBodyPoint(point, pose) {
      const x1 = point.x + pose.bodyShiftX;
      const y1 = point.y + pose.bodyY;
      const pivotX = pose.pivotX + pose.bodyShiftX;
      const pivotY = 356;
      const a = pose.bodyRotate * Math.PI / 180;
      const c = Math.cos(a);
      const s = Math.sin(a);
      const dx = x1 - pivotX;
      const dy = y1 - pivotY;
      return { x: pivotX + dx * c - dy * s, y: pivotY + dx * s + dy * c };
    }

function applyIdleLookGeometry(pose) {
      lookState.yaw = pose.lookYaw;
      lookState.pitch = 0;
      const active = headLookActive();
      const cheek = cheekPath();
      const offsets = elementOffsets();
      const ears = earState();

      setRootAttr("head-cap-fill", "d", headCapPath());
      setRootAttr("cheek-muzzle-fill", "d", cheek);
      setRootAttr("idle-look-blush-clip-path", "d", cheek);
      setRootAttr("left-cheek-crease", "d", creasePath("left"));
      setRootAttr("right-cheek-crease", "d", creasePath("right"));
      setRootAttr("left-cheek-crease", "stroke-width", active ? "2.6" : "3");
      setRootAttr("right-cheek-crease", "stroke-width", active ? "2.6" : "3");
      setRootAttr("idle-look-blush-clip-wrapper", "transform", "");
      setRootAttr("idle-look-blush-transform", "transform", active ? blushPlaneTransform() : "");
      setRootAttr("left-ear", "transform", active ? translate(ears.left.x, ears.left.y) : "");
      setRootAttr("right-ear", "transform", active ? translate(ears.right.x, ears.right.y) : "");
      setRootAttr("left-ear-outer", "r", fmt(mix(34, 37.4, ears.left.grow)));
      setRootAttr("left-ear-inner", "r", fmt(mix(18, 19.8, ears.left.grow)));
      setRootAttr("right-ear-outer", "r", fmt(mix(34, 37.4, ears.right.grow)));
      setRootAttr("right-ear-inner", "r", fmt(mix(18, 19.8, ears.right.grow)));
      setRootAttr("left-eye", "rx", "12.5");
      setRootAttr("right-eye", "rx", "12.5");
      setRootAttr("left-eye", "ry", "17");
      setRootAttr("right-eye", "ry", "17");
      setRootAttr("left-eye", "transform", centeredTransform({ x: 138, y: 157 }, offsets.leftEye.dx, offsets.leftEye.dy));
      setRootAttr("right-eye", "transform", centeredTransform({ x: 237, y: 157 }, offsets.rightEye.dx, offsets.rightEye.dy));
      setRootAttr("left-blush", "transform", centeredTransform({ x: 92, y: 185 }, offsets.leftBlush.dx, offsets.leftBlush.dy, offsets.leftBlush.sx, offsets.leftBlush.sy));
      setRootAttr("right-blush", "transform", centeredTransform({ x: 281, y: 185 }, offsets.rightBlush.dx, offsets.rightBlush.dy, offsets.rightBlush.sx, offsets.rightBlush.sy));
      setRootAttr("nose-mouth", "transform", "");
      setRootAttr("sunglasses", "transform", "");
    }

function applyExpression(pose) {
      const focus = clamp(pose.focusExpr, 0, 1);
      const happy = clamp(pose.happyExpr, 0, 1);
      const leftBrow = root.querySelector("#left-brow");
      const rightBrow = root.querySelector("#right-brow");
      if (leftBrow) leftBrow.setAttribute("d", expressionBrowPath("left", focus, happy));
      if (rightBrow) rightBrow.setAttribute("d", expressionBrowPath("right", focus, happy));

      const mouthInset = mix(state.focusMouthInset * focus, state.happyMouthInset, happy);
      applyMouthInset(root.querySelector("#mouth-left"), mouthInset);
      applyMouthInset(root.querySelector("#mouth-right"), mouthInset);
    }

function expressionBrowPath(side, focus, happy) {
      const paths = BROW_PATHS[side];
      const focusT = clamp(focus * state.focusBrow, 0, 1.2);
      const happyT = clamp(happy * state.happyBrow, 0, 1.2);
      let points = paths.base.map((point, index) => mixBrowPoint(point, paths.focus[index], focusT));
      points = points.map((point, index) => mixBrowPoint(point, paths.happy[index], happyT));
      return `M ${fmt(points[0][0])} ${fmt(points[0][1])} C ${fmt(points[1][0])} ${fmt(points[1][1])} ${fmt(points[2][0])} ${fmt(points[2][1])} ${fmt(points[3][0])} ${fmt(points[3][1])}`;
    }

function mixBrowPoint(a, b, t) {
      return [mix(a[0], b[0], t), mix(a[1], b[1], t)];
    }

function applyMouthInset(node, inset) {
      if (!node) return;
      node.removeAttribute("clip-path");
      node.setAttribute("stroke-linecap", "round");
      const amount = clamp(inset, 0, 28);
      if (amount <= 0.05 || !node.getTotalLength) {
        node.removeAttribute("stroke-dasharray");
        node.removeAttribute("stroke-dashoffset");
        return;
      }
      const length = node.getTotalLength();
      const visibleLength = Math.max(0.1, length - amount);
      node.setAttribute("stroke-dasharray", `${fmt(visibleLength)} ${fmt(length + 24)}`);
      node.setAttribute("stroke-dashoffset", "0");
    }

function idleLookLayerTransform(id) {
      if (!headLookActive()) return "";
      if (id === "face-layer") return facePlaneTransform(true);
      if (id === "head-tufts") return tuftLookTransform();
      return "";
    }

function setRootAttr(id, name, value) {
      const node = root.querySelector(`#${id}`) || stageSvg.querySelector(`#${id}`);
      if (!node) return;
      if (value === null || value === undefined || value === "") node.removeAttribute(name);
      else node.setAttribute(name, value);
    }

function headLookActive() {
      return Math.abs(lookState.yaw) > 0.001 || Math.abs(lookState.pitch) > 0.001;
    }

function axisT(value) {
      return smooth01(Math.abs(value) / 100);
    }

function diagonalFactor() {
      return Math.abs(lookState.yaw) / 100 * Math.abs(lookState.pitch) / 100;
    }

function trimmed(value, trimScale = 1) {
      return value * (1 - diagonalFactor() * 0.15 * trimScale);
    }

function smooth01(value) {
      const t = clamp(value, 0, 1);
      return t * t * (3 - 2 * t);
    }

function smoothRange(start, end, value) {
      return smooth01(clamp((value - start) / (end - start), 0, 1));
    }

function translate(x, y) {
      return Math.abs(x) < 1e-6 && Math.abs(y) < 1e-6 ? "" : `translate(${fmt(x)} ${fmt(y)})`;
    }

function mixPoint(a, b, t) {
      return { x: mix(a.x, b.x, t), y: mix(a.y, b.y, t) };
    }

function numbers(value) {
      return (value.match(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi) || []).map(Number);
    }

function transformPathPairs(path, fn) {
      const values = numbers(path);
      const output = [];
      for (let i = 0; i < values.length; i += 2) {
        const point = fn({ x: values[i], y: values[i + 1] });
        output.push(point.x, point.y);
      }
      let index = 0;
      return path.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, () => fmt(output[index++]));
    }

function interpolateNumberString(from, to, t) {
      const a = numbers(from);
      const b = numbers(to);
      let index = 0;
      if (!from || !to || a.length !== b.length) return t < 1 ? from : to;
      return from.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, () => {
        const value = fmt(mix(a[index], b[index] ?? a[index - 1], t));
        index += 1;
        return value;
      });
    }

function transformTopPoint(point, dir) {
      const axisX = dir < 0 ? 125 : 249;
      const axisTravel = (axisX - VIEW_W / 2) * 0.75;
      const localX = point.x - axisX;
      const next = { x: axisTravel + axisX + localX, y: point.y };
      const weightT = clamp((point.x - RAW_ANCHORS.A.x) / (RAW_ANCHORS.G.x - RAW_ANCHORS.A.x), 0, 1);
      const weight = Math.pow(Math.sin(Math.PI * weightT), 0.9);
      return { x: point.x + (next.x - point.x) * weight, y: point.y };
    }

function catmullPath(points, tension = 0.72, sharpness = 0.34) {
      const segs = [`M${fmt(points[0].x)} ${fmt(points[0].y)}`];
      for (let i = 0; i < points.length - 1; i += 1) {
        const p0 = points[Math.max(0, i - 1)];
        const p1 = points[i];
        const p2 = points[i + 1];
        const p3 = points[Math.min(points.length - 1, i + 2)];
        const nearBridge = ["C", "D", "E"].includes(p1.id) || ["C", "D", "E"].includes(p2.id);
        const localTension = tension * (nearBridge ? (1 - sharpness * 0.42) : 1);
        const c1 = {
          x: p1.x + (p2.x - p0.x) * localTension / 6,
          y: p1.y + (p2.y - p0.y) * localTension / 6
        };
        const c2 = {
          x: p2.x - (p3.x - p1.x) * localTension / 6,
          y: p2.y - (p3.y - p1.y) * localTension / 6
        };
        segs.push(`C${fmt(c1.x)} ${fmt(c1.y)} ${fmt(c2.x)} ${fmt(c2.y)} ${fmt(p2.x)} ${fmt(p2.y)}`);
      }
      return segs.join(" ");
    }

function yawFacePath() {
      const dir = Math.sign(lookState.yaw);
      const t = axisT(lookState.yaw);
      if (!dir || t <= 0.001 || TOP_CHAIN.some((id) => !RAW_ANCHORS[id])) return LOOK_BASE.cheekD;
      const top = TOP_CHAIN.map((id) => {
        const start = RAW_ANCHORS[id];
        const end = transformTopPoint(start, dir);
        return { id, ...mixPoint(start, end, t) };
      });
      const sideTail = dir < 0 ? LEFT_TAIL : RIGHT_TAIL;
      const tail = FRONT_TAIL.map((seg, index) => {
        const mixed = seg.map((value, numberIndex) => mix(value, sideTail[index][numberIndex], t));
        return `C${fmt(mixed[0])} ${fmt(mixed[1])} ${fmt(mixed[2])} ${fmt(mixed[3])} ${fmt(mixed[4])} ${fmt(mixed[5])}`;
      }).join(" ");
      return `${catmullPath(top)} ${tail}Z`;
    }

function faceLowerEffect() {
      if (lookState.pitch <= 0) return 0;
      return axisT(lookState.pitch) * mix(0.45, 1, axisT(lookState.yaw));
    }

function faceLowerWrappedPoint(point) {
      const effect = faceLowerEffect();
      if (effect <= 0.001) return point;
      const lower = smoothRange(238, 263, point.y);
      if (lower <= 0.001) return point;
      const side = Math.sign(point.x - 187);
      return { x: point.x + side * 6 * effect * lower * 0.3, y: point.y + 12 * effect * lower };
    }

function faceLowerWrappedPath(path) {
      return transformPathPairs(path, faceLowerWrappedPoint);
    }

function pitchDeltaY(y) {
      if (lookState.pitch === 0) return 0;
      const sign = Math.sign(lookState.pitch);
      const t = axisT(lookState.pitch);
      const lowerWeight = clamp((y - 166) / 92, 0, 1);
      if (sign < 0) return mix(PITCH_UP.axis, PITCH_UP.lower, lowerWeight) * t;
      return mix(PITCH_DOWN.axis, PITCH_DOWN.lower, lowerWeight) * t;
    }

function warpPathForPitch(path) {
      let index = 0;
      return path.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, (value) => {
        const n = Number(value);
        const next = index % 2 === 1 ? n + pitchDeltaY(n) : n;
        index += 1;
        return fmt(next);
      });
    }

function cheekPath() {
      return faceLowerWrappedPath(warpPathForPitch(yawFacePath()));
    }

function headCapPath() {
      const yawT = axisT(lookState.yaw);
      const dir = Math.sign(lookState.yaw);
      const yawTarget = dir > 0 ? RIGHT_HEAD_CAP_D : LEFT_HEAD_CAP_D;
      const yawPath = dir ? interpolateNumberString(LOOK_BASE.headCapD, yawTarget, yawT) : LOOK_BASE.headCapD;
      let index = 0;
      return yawPath.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, (value) => {
        const n = Number(value);
        if (index % 2 === 0) {
          index += 1;
          return fmt(n);
        }
        const topWeight = clamp((120 - n) / 80, 0, 1);
        const sideWeight = clamp((n - 120) / 70, 0, 1);
        const sign = Math.sign(lookState.pitch);
        const t = axisT(lookState.pitch);
        const delta = sign < 0 ? (2 * topWeight - 5.61 * sideWeight) * t : (-1.87 * topWeight + 7.28 * sideWeight) * t;
        index += 1;
        return fmt(n + delta);
      });
    }

function creasePath(side) {
      const isLeft = side === "left";
      const base = LOOK_BASE[isLeft ? "leftCreaseD" : "rightCreaseD"];
      const sideSign = isLeft ? 1 : -1;
      const startX = isLeft ? 62 : 312;
      const baseLength = 38;
      const yawT = axisT(lookState.yaw);
      const yawPull = Math.sign(lookState.yaw) * yawT;
      const pitchT = axisT(lookState.pitch);
      return transformPathPairs(base, (point) => {
        const along = isLeft ? clamp((point.x - 62) / baseLength, 0, 1) : clamp((312 - point.x) / baseLength, 0, 1);
        const next = { x: startX + (point.x - startX), y: point.y };
        next.x += yawPull * (isLeft ? 1 : -1) * mix(3, 6, along);
        next.x += sideSign * mix(1.8, 2.4, along) * pitchT;
        next.y += pitchDeltaY(point.y);
        return faceLowerWrappedPoint(next);
      });
    }

function facePlaneTransform(withPitchScale) {
      const dir = Math.sign(lookState.yaw);
      const yawT = axisT(lookState.yaw);
      const axis = 187 + dir * 62 * yawT;
      const dx = dir * 46.5 * yawT;
      const pitchSign = Math.sign(lookState.pitch);
      const pitchT = axisT(lookState.pitch);
      const pitchData = pitchSign < 0 ? PITCH_UP : PITCH_DOWN;
      const dy = trimmed(pitchData.faceDy * pitchT, 0.45);
      const sy = withPitchScale ? mix(1, pitchData.faceSy, pitchT) : 1;
      return `translate(${fmt(dx)} ${fmt(dy)}) translate(${fmt(axis)} 172) skewX(0) scale(1 ${fmt(sy)}) translate(${fmt(-axis)} -172)`;
    }

function blushPlaneTransform() {
      const dir = Math.sign(lookState.yaw);
      const yawT = axisT(lookState.yaw);
      const axis = 187 + dir * 62 * yawT;
      const dx = dir * 46.5 * yawT;
      const pitchSign = Math.sign(lookState.pitch);
      const pitchT = axisT(lookState.pitch);
      const pitchData = pitchSign < 0 ? PITCH_UP : PITCH_DOWN;
      const dy = trimmed(pitchData.blushDy * pitchT, 0.35);
      return `translate(${fmt(dx)} ${fmt(dy)}) translate(${fmt(axis)} 172) skewX(0) scale(1 1) translate(${fmt(-axis)} -172)`;
    }

function centeredTransform(origin, dx, dy, sx = 1, sy = 1) {
      if (Math.abs(dx) < 1e-6 && Math.abs(dy) < 1e-6 && Math.abs(sx - 1) < 1e-6 && Math.abs(sy - 1) < 1e-6) return "";
      return `translate(${fmt(origin.x + dx)} ${fmt(origin.y + dy)}) scale(${fmt(sx)} ${fmt(sy)}) translate(${fmt(-origin.x)} ${fmt(-origin.y)})`;
    }

function elementOffsets() {
      const dir = Math.sign(lookState.yaw);
      const yawT = axisT(lookState.yaw);
      const pitchSign = Math.sign(lookState.pitch);
      const pitchT = axisT(lookState.pitch);
      const pitchUp = pitchSign < 0;
      const pitchEye = pitchUp ? -0.56 * pitchT : 0;
      const pitchBlushDx = pitchUp ? 3.5 * pitchT : -1.8 * pitchT;
      const yawLeftEye = dir < 0 ? -2 * yawT : 0;
      const yawRightEye = dir > 0 ? 2 * yawT : 0;
      const leftBlushYaw = dir < 0
        ? { dx: 6.5 * yawT, dy: 0, sx: 1, sy: 1 }
        : { dx: -24 * yawT, dy: 20.5 * yawT, sx: mix(1, 1.09, yawT), sy: mix(1, 1.1, yawT) };
      const rightBlushYaw = dir < 0
        ? { dx: 25 * yawT, dy: 20.5 * yawT, sx: mix(1, 1.09, yawT), sy: mix(1, 1.1, yawT) }
        : { dx: -5.5 * yawT, dy: 0, sx: 1, sy: 1 };
      return {
        leftEye: { dx: yawLeftEye, dy: pitchEye },
        rightEye: { dx: yawRightEye, dy: pitchEye },
        leftBlush: { dx: leftBlushYaw.dx + pitchBlushDx, dy: leftBlushYaw.dy, sx: leftBlushYaw.sx, sy: leftBlushYaw.sy },
        rightBlush: { dx: rightBlushYaw.dx - pitchBlushDx, dy: rightBlushYaw.dy, sx: rightBlushYaw.sx, sy: rightBlushYaw.sy }
      };
    }

function earState() {
      const dir = Math.sign(lookState.yaw);
      const yawT = axisT(lookState.yaw);
      const pitchSign = Math.sign(lookState.pitch);
      const pitchT = axisT(lookState.pitch);
      const pitchData = pitchSign < 0 ? PITCH_UP : PITCH_DOWN;
      const pitchDy = pitchData.earDy * pitchT;
      const left = { x: 0, y: pitchDy, grow: 0 };
      const right = { x: 0, y: pitchDy, grow: 0 };
      if (dir < 0) {
        left.x += -3.5 * yawT;
        left.y += 3.5 * yawT;
        right.grow = smoothRange(0.12, 1, yawT);
      } else if (dir > 0) {
        right.x += -9.5 * yawT;
        right.y += 3.5 * yawT;
        left.grow = smoothRange(0.12, 1, yawT);
      }
      return { left, right };
    }

function tuftLookTransform() {
      const dir = Math.sign(lookState.yaw);
      const yawT = axisT(lookState.yaw);
      const pitchSign = Math.sign(lookState.pitch);
      const pitchT = axisT(lookState.pitch);
      const pitchData = pitchSign < 0 ? PITCH_UP : PITCH_DOWN;
      const yawDx = dir < 0 ? -21.7 * yawT : dir > 0 ? -10.3 * yawT : 0;
      const pitchDy = pitchData.tuftDy * pitchT;
      return translate(yawDx, pitchDy);
    }

function applyFeetPose(pose) {
      const leftFoot = root.querySelector("#left-foot");
      const rightFoot = root.querySelector("#right-foot");
      const leftSupportScale = 1 + 0.045 * pose.supportLeft + pose.landing * 0.015 * pose.supportLeft;
      const rightSupportScale = 1 + 0.045 * pose.supportRight + pose.landing * 0.015 * pose.supportRight;

      if (leftFoot) {
        if (pose.tappingFoot === "left") {
          leftFoot.setAttribute("transform", `translate(0 ${fmt(-pose.heelLift)}) rotate(${fmt(pose.footRotate)} 104 405)`);
        } else {
          leftFoot.setAttribute("transform", supportFootTransform("left", leftSupportScale, pose.supportLeft));
        }
      }
      if (rightFoot) {
        if (pose.tappingFoot === "right") {
          rightFoot.setAttribute("transform", `translate(0 ${fmt(-pose.heelLift)}) rotate(${fmt(-pose.footRotate)} 270 405)`);
        } else {
          rightFoot.setAttribute("transform", supportFootTransform("right", rightSupportScale, pose.supportRight));
        }
      }

      const markOpacity = state.showTapMarks ? clamp(pose.landing * state.tapPower, 0, 1) : 0;
      leftTapMarks.setAttribute("opacity", pose.tappingFoot === "left" ? fmt(markOpacity) : "0");
      rightTapMarks.setAttribute("opacity", pose.tappingFoot === "right" ? fmt(markOpacity) : "0");
      tapMarkLayer.style.display = state.showTapMarks ? "" : "none";
    }

function supportFootTransform(side, scale, support) {
      if (side === "left") {
        return `translate(${fmt(-3 * support)} 0) scale(${fmt(scale)} 1) translate(${fmt(104 * (1 - scale) / scale)} 0)`;
      }
      return `translate(${fmt(3 * support)} 0) scale(${fmt(scale)} 1) translate(${fmt(270 * (1 - scale) / scale)} 0)`;
    }

function applySessions(pose) {
      sessionLayer.style.display = state.showSessionBoxes ? "" : "none";
      const clock = pose.ms / 1000;
      const leftProgress = pose.phase === "turnRight" ? 1 : pose.leftTyping;
      const rightProgress = pose.phase === "turnLeft" ? 1 : pose.rightTyping;
      renderLeftBubble({ active: pose.leftActive, progress: leftProgress, running: pose.activeSession === "left" }, clock);
      renderRightBubble({ active: pose.rightActive, progress: rightProgress, running: pose.activeSession === "right" }, clock);
    }

function renderBubbleRoot(node, side, active, clock) {
      const pose = BUBBLE_POSES[side];
      if (active <= 0.001) {
        node.style.display = "none";
        node.setAttribute("opacity", "0");
        node.removeAttribute("filter");
        return false;
      }
      node.style.display = "";
      const bobPhase = side === "right" ? Math.PI : 0;
      const bob = Math.sin(clock * Math.PI * 2 + bobPhase) * active * 1.9 * state.bodySway;
      const scale = pose.scale * (1 + active * 0.03 * state.typingPower);
      node.setAttribute("transform", `translate(${fmt(pose.x)} ${fmt(pose.y + bob)}) scale(${fmt(scale)})`);
      node.setAttribute("opacity", fmt(side === "left" ? 0.72 + active * 0.22 : 0.78 + active * 0.18));
      node.setAttribute("filter", active > 0.55 ? "url(#bubbleGlow)" : "url(#bubbleShadow)");
      return true;
    }

function renderLeftBubble(info, clock) {
      const active = clamp(info.active * (0.52 + state.typingPower * 0.42), 0, 1.15);
      const progress = info.running ? clamp(info.progress * state.typingPower, 0, 1) : clamp(info.progress, 0, 1);
      if (!renderBubbleRoot(bubbleLeft.root, "left", active, clock)) return;

      bubbleLeft.shellStroke.setAttribute("stroke-opacity", fmt(0.30 + active * 0.44));
      bubbleLeft.shellFill.setAttribute("opacity", fmt(0.72 + active * 0.25));

      const iconProgress = easeOutCubic(clamp(progress / 0.16, 0, 1));
      bubbleLeft.icon.forEach((path, index) => {
        const p = easeOutCubic(clamp((iconProgress - index * 0.14) / 0.72, 0, 1));
        path.setAttribute("stroke-dasharray", "1");
        path.setAttribute("stroke-dashoffset", fmt(1 - p));
        path.setAttribute("opacity", fmt(0.38 + active * 0.40 + p * 0.2));
      });

      let cursorX = 72;
      let cursorY = 99;
      bubbleLeft.lines.forEach((line, index) => {
        const p = easeOutCubic(clamp((progress - line.start) / line.span, 0, 1));
        const width = Math.max(0.01, line.max * p);
        line.el.setAttribute("width", fmt(width));
        line.el.setAttribute("opacity", fmt(0.10 + active * 0.18 + p * 0.70));
        if (p > 0 && p < 1) {
          cursorX = line.x + width + 7;
          cursorY = line.y - 1;
        } else if (p >= 1 && progress < 0.94) {
          cursorX = line.x + width + 7;
          cursorY = line.y - 1;
        }

        const dotIndex = index <= 1 ? 0 : index === 2 ? 1 : index <= 4 ? 2 : 3;
        const dot = bubbleLeft.dots[dotIndex];
        if (dot) {
          const dotP = easeOutCubic(clamp((progress - (line.start - 0.04)) / 0.1, 0, 1));
          dot.setAttribute("opacity", fmt(0.14 + dotP * (0.34 + active * 0.36)));
        }
      });

      bubbleLeft.dots.forEach((dot, index) => {
        const rowStart = [0.12, 0.30, 0.48, 0.66][index];
        const p = easeOutCubic(clamp((progress - rowStart) / 0.12, 0, 1));
        const pulse = info.running ? pulse01(clock * 1.4 + index * 0.17) : 0.35;
        dot.setAttribute("r", fmt(5.2 + p * 0.9 + active * pulse * 0.7));
        dot.setAttribute("opacity", fmt(0.14 + p * (0.36 + active * 0.38)));
      });

      const line1DotP = easeOutCubic(clamp((progress - 0.30) / 0.12, 0, 1));
      bubbleLeft.line1Dot.setAttribute("opacity", fmt(0.08 + line1DotP * (0.45 + active * 0.45)));
      bubbleLeft.line1Dot.setAttribute("r", fmt(5.4 + line1DotP * 1.4));

      const blink = info.running && progress < 0.96 ? pulse01(clock * 5.6) : 0;
      bubbleLeft.cursor.setAttribute("x", fmt(cursorX));
      bubbleLeft.cursor.setAttribute("y", fmt(cursorY));
      bubbleLeft.cursor.setAttribute("opacity", info.running && active > 0.45 ? fmt(0.18 + blink * 0.82) : "0");
    }

function renderRightBubble(info, clock) {
      const active = clamp(info.active * (0.52 + state.typingPower * 0.42), 0, 1.15);
      const progress = clamp(info.progress, 0, 1);
      if (!renderBubbleRoot(bubbleRight.root, "right", active, clock)) return;

      bubbleRight.shellStroke.setAttribute("stroke-opacity", fmt(0.24 + active * 0.40));
      bubbleRight.shellGlow.setAttribute("opacity", fmt(0.04 + active * 0.09));
      bubbleRight.chat.setAttribute("opacity", fmt(0.70 + active * 0.24));

      bubbleRight.chatDots.forEach((dot, index) => {
        const wave = pulse01(clock * 2.2 + index * 0.19);
        const lift = info.running ? (wave - 0.5) * active * 2.8 * state.bodySway : 0;
        dot.setAttribute("transform", `translate(0 ${fmt(-lift)})`);
        dot.setAttribute("r", fmt(6.8 + active * (0.7 + wave * 1.0)));
        dot.setAttribute("opacity", fmt(0.48 + active * (0.26 + wave * 0.2)));
      });

      bubbleRight.bottomDots.forEach((dot, index) => {
        const wave = pulse01(clock * 1.7 - index * 0.22);
        dot.setAttribute("r", fmt(8.1 + active * wave * 2.2));
        dot.setAttribute("opacity", fmt(0.26 + active * (0.26 + wave * 0.36)));
      });

      bubbleRight.checks.forEach((path, index) => {
        const p = easeOutCubic(clamp((progress - (0.18 + index * 0.22)) / 0.15, 0, 1));
        path.setAttribute("stroke-dasharray", "1");
        path.setAttribute("stroke-dashoffset", fmt(1 - p));
        path.setAttribute("opacity", fmt(0.10 + active * 0.12 + p * 0.74));
      });

      bubbleRight.tasks.forEach((path, index) => {
        const p = easeOutCubic(clamp((progress - (0.28 + index * 0.22)) / 0.18, 0, 1));
        path.setAttribute("stroke-dasharray", "1");
        path.setAttribute("stroke-dashoffset", fmt(1 - p));
        path.setAttribute("opacity", fmt(0.10 + active * 0.10 + p * 0.72));
      });
    }

function applyGuides(pose) {
      guideLayer.style.display = state.showGuides ? "" : "none";
      weightAxis.setAttribute("x1", fmt(pose.weightAxisX));
      weightAxis.setAttribute("x2", fmt(pose.weightAxisX));
      weightDot.setAttribute("cx", fmt(pose.weightAxisX));
      const rayX = 187 + pose.look * 72;
      const rayY = pose.look < 0 ? 58 : 60;
      lookRay.setAttribute("x1", fmt(187 + pose.bodyShiftX * 0.25));
      lookRay.setAttribute("y1", "155");
      lookRay.setAttribute("x2", fmt(rayX));
      lookRay.setAttribute("y2", fmt(rayY));
      lookRay.setAttribute("opacity", fmt(0.25 + 0.45 * Math.abs(pose.look)));
    }

function applyArmsColorTune() {
      const baseImage = root.querySelector("#crossedArmsBaseImage");
      const tintImage = root.querySelector("#crossedArmsTintImage");
      if (!baseImage || !tintImage) return;
      baseImage.style.filter = `contrast(${fmt(state.armsContrast)}) brightness(${fmt(state.armsBrightness)})`;
      tintImage.setAttribute("opacity", fmt(state.armsTint));
    }

function applyArmsOutlineTune() {
      const outline = root.querySelector("#crossedArmsHandLineLayer");
      if (!outline) return;
      outline.setAttribute("opacity", fmt(state.armsOutlineOpacity));
      outline.querySelectorAll("path").forEach((path) => {
        const opacity = Number(path.dataset.opacity || 1);
        const width = Number(path.dataset.width || 1);
        path.setAttribute("opacity", fmt(opacity));
        path.setAttribute("stroke-width", fmt(state.armsOutlineWidth * width));
      });
    }

function armsTransform(arms) {
      const defaults = { x: 187, y: 292 };
      const dx = arms.x - defaults.x;
      const dy = arms.y - defaults.y;
      const sx = arms.scale * arms.scaleX;
      const sy = arms.scale * arms.scaleY;
      return `translate(${fmt(dx)} ${fmt(dy)}) rotate(${fmt(arms.rotate)} ${defaults.x} ${defaults.y}) translate(${defaults.x} ${defaults.y}) scale(${fmt(sx)} ${fmt(sy)}) translate(${-defaults.x} ${-defaults.y})`;
    }

function armsForPose(pose) {
      if (pose.side < 0) return mixArms(ARMS_POSES.center, ARMS_POSES.left, clamp(-pose.side, 0, 1));
      return mixArms(ARMS_POSES.center, ARMS_POSES.right, clamp(pose.side, 0, 1));
    }

function mixArms(a, b, t) {
      return {
        x: mix(a.x, b.x, t),
        y: mix(a.y, b.y, t),
        scale: mix(a.scale, b.scale, t),
        scaleX: mix(a.scaleX, b.scaleX, t),
        scaleY: mix(a.scaleY, b.scaleY, t),
        rotate: mix(a.rotate, b.rotate, t),
        opacity: mix(a.opacity, b.opacity, t)
      };
    }

function heldGlance(p) {
      return easeInOutCubic(clamp((p - 0.04) / 0.18, 0, 1));
    }

function returnLook(p) {
      return 1 - easeInOutCubic(clamp(p / 0.28, 0, 1));
    }

function expressionGate(p) {
      return easeInOutCubic(clamp(p / 0.16, 0, 1)) * (1 - easeInOutCubic(clamp((p - 0.92) / 0.08, 0, 1)));
    }

function happyPulse(p) {
      const up = easeOutCubic(clamp(p / 0.20, 0, 1));
      const down = 1 - easeInOutCubic(clamp((p - 0.78) / 0.22, 0, 1));
      return up * down;
    }

function workGate(p) {
      return easeInOutCubic(clamp(p / 0.18, 0, 1)) * easeInOutCubic(clamp((1 - p) / 0.16, 0, 1));
    }

function mix(a, b, t) {
      return a + (b - a) * t;
    }

function clamp(value, min, max) {
      return Math.max(min, Math.min(max, value));
    }

function positiveMod(value, mod) {
      return ((value % mod) + mod) % mod;
    }

function pulse01(t) {
      return 0.5 + 0.5 * Math.sin(Math.PI * 2 * t);
    }

function easeOutCubic(t) {
      const u = 1 - clamp(t, 0, 1);
      return 1 - u * u * u;
    }

function easeInOutCubic(t) {
      t = clamp(t, 0, 1);
      return t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;
    }

function fmt(value) {
      return Number(value).toFixed(3).replace(/\.?0+$/, "");
    }

function round(value, digits = 2) {
      const scale = 10 ** digits;
      return Math.round(value * scale) / scale;
    }
})();
